public static ArrayList<Integer> next_permutation(ArrayList<Integer> perm) {
    // find the rightmost i with a[i] < a[i+1]
    int i = perm.size() - 1;
    while (i > 0 && perm.get(i) <= perm.get(i-1)) {
        i--;
    }
    // if no such i exists, this permutation is the last permutation
    if (i <= 0) {
        return new ArrayList<Integer>();
    }

    // find the rightmost j with a[i] < a[j]
    int j = perm.size() - 1;
    while (perm.get(j) <= perm.get(i-1)) {
        j--;
    }

    // swap a[i-1] and a[j]
    int temp = perm.get(i-1);
    perm.set(i-1, perm.get(j));
    perm.set(j, temp);

